-- Actualiza followersCount y followingCount en base a la tabla UserFollows
UPDATE Users u SET 
    u.followersCount = COALESCE((SELECT COUNT(*) FROM UserFollows WHERE followeeId = u.id), 0),
    u.followingCount = COALESCE((SELECT COUNT(*) FROM UserFollows WHERE followerId = u.id), 0);
